import (
	"bytes"
	"context"
	"os"
	"path/filepath"
	"strings"

	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

// isBenignMaterializedTrackedSymlink reports whether path was tracked as a
// symlink in HEAD but is now a directory whose tree matches the symlink target
// exactly. Tool syncs that materialize skill symlinks this way are benign and
// must not block pre-claim.
func isBenignMaterializedTrackedSymlink(projectRoot, path string) bool {
	target, ok, err := trackedSymlinkTarget(projectRoot, path)
	if err != nil || !ok || target == "" {
		return false
	}

	worktreePath := filepath.Join(projectRoot, filepath.FromSlash(path))
	info, err := os.Lstat(worktreePath)
	if err != nil || info.Mode()&os.ModeSymlink != 0 || !info.IsDir() {
		return false
	}

	resolvedTarget := target
	if !filepath.IsAbs(resolvedTarget) {
		resolvedTarget = filepath.Join(filepath.Dir(worktreePath), resolvedTarget)
	}
	resolvedTarget = filepath.Clean(resolvedTarget)

	same, err := sameFileTree(worktreePath, resolvedTarget)
	return err == nil && same
}

func trackedSymlinkTarget(projectRoot, path string) (string, bool, error) {
	out, err := internalgit.Command(context.Background(), projectRoot, "ls-tree", "-z", "HEAD", "--", path).Output()
	if err != nil {
		return "", false, err
	}
	entry := strings.TrimRight(string(out), "\x00")
	if entry == "" {
		return "", false, nil
	}

	header, _, ok := strings.Cut(entry, "\t")
	if !ok {
		return "", false, nil
	}
	fields := strings.Fields(header)
	if len(fields) < 3 || fields[0] != "120000" || fields[1] != "blob" {
		return "", false, nil
	}

	targetOut, err := internalgit.Command(context.Background(), projectRoot, "cat-file", "-p", fields[2]).Output()
	if err != nil {
		return "", false, err
	}
	return strings.TrimSpace(string(targetOut)), true, nil
}

func sameFileTree(left, right string) (bool, error) {
	leftInfo, err := os.Lstat(left)
	if err != nil {
		return false, err
	}
	rightInfo, err := os.Lstat(right)
	if err != nil {
		return false, err
	}

	leftSymlink := leftInfo.Mode()&os.ModeSymlink != 0
	rightSymlink := rightInfo.Mode()&os.ModeSymlink != 0
	if leftSymlink || rightSymlink {
		if leftSymlink != rightSymlink {
			return false, nil
		}
		leftTarget, err := os.Readlink(left)
		if err != nil {
			return false, err
		}
		rightTarget, err := os.Readlink(right)
		if err != nil {
			return false, err
		}
		return leftTarget == rightTarget, nil
	}

	leftDir := leftInfo.IsDir()
	rightDir := rightInfo.IsDir()
	if leftDir || rightDir {
		if leftDir != rightDir {
			return false, nil
		}
		if leftInfo.Mode().Perm() != rightInfo.Mode().Perm() {
			return false, nil
		}
		leftEntries, err := os.ReadDir(left)
		if err != nil {
			return false, err
		}
		rightEntries, err := os.ReadDir(right)
		if err != nil {
			return false, err
		}
		if len(leftEntries) != len(rightEntries) {
			return false, nil
		}
		for i := range leftEntries {
			if leftEntries[i].Name() != rightEntries[i].Name() {
				return false, nil
			}
			same, err := sameFileTree(
				filepath.Join(left, leftEntries[i].Name()),
				filepath.Join(right, rightEntries[i].Name()),
			)
			if err != nil || !same {
				return same, err
			}
		}
		return true, nil
	}

	if !leftInfo.Mode().IsRegular() || !rightInfo.Mode().IsRegular() {
		return false, nil
	}
	if leftInfo.Mode().Perm() != rightInfo.Mode().Perm() {
		return false, nil
	}
	leftBytes, err := os.ReadFile(left)
	if err != nil {
		return false, err
	}
	rightBytes, err := os.ReadFile(right)
	if err != nil {
		return false, err
	}
	return bytes.Equal(leftBytes, rightBytes), nil
}
